// Parse Twilio POST body
const body = $input.first().json.body || $input.first().json;

const callSid      = body.CallSid      || '';
const speechResult = (body.SpeechResult || '').trim();
const callStatus   = body.CallStatus   || 'in-progress';
const fromPhone    = body.From         || '';
const toPhone      = body.To           || '';

// Deepgram Nova-2 returns SpeechResult via Twilio's <Gather>
// Confidence score is also available as SpeechResultConfidence
const confidence   = parseFloat(body.SpeechResultConfidence || '1.0');

const isNewCall = !speechResult && callStatus !== 'completed';
const isEnded   = callStatus === 'completed';

return [{ json: { callSid, speechResult, callStatus, fromPhone, toPhone, confidence, isNewCall, isEnded } }];

// -------------------------------------------------------
// GREETING — ElevenLabs TTS via booking API
// -------------------------------------------------------
const { callSid, fromPhone } = $input.first().json;

const WEBHOOK_URL       = $env.N8N_WEBHOOK_URL;
const BOOKING_API_URL   = 'http://booking_api:8000';
const BOOKING_API_KEY   = $env.BOOKING_API_KEY;
const BOOKING_PUBLIC_URL = $env.BOOKING_API_PUBLIC_URL;

const greetingText = 'Welcome to Grand Choice Inn and Suites. I am your virtual assistant. I can help you check room availability, make a reservation, confirm an existing booking, or answer questions about our hotel. How can I help you today?';

// Generate ElevenLabs audio for greeting
let audioUrl = null;
try {
  const ttsResp = await fetch(`${BOOKING_API_URL}/tts`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'x-api-key': BOOKING_API_KEY },
    body: JSON.stringify({ text: greetingText }),
  });
  if (ttsResp.ok) {
    const ttsData = await ttsResp.json();
    audioUrl = ttsData.audio_url;
  }
} catch (e) {
  // fallback to Twilio TTS if ElevenLabs fails
}

// Build TwiML — use <Play> if we have ElevenLabs audio, else <Say>
const speechContent = audioUrl
  ? `<Play>${audioUrl}</Play>`
  : `<Say voice="Polly.Joanna" language="en-US">${greetingText}</Say>`;

const twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Gather input="speech" action="${WEBHOOK_URL}/webhook/voice-agent" method="POST"
          speechTimeout="3" language="en-US"
          speechModel="nova2-general"
          enhanced="true">
    ${speechContent}
  </Gather>
  <Redirect method="POST">${WEBHOOK_URL}/webhook/voice-agent</Redirect>
</Response>`;

return [{ json: { twiml, callSid, fromPhone } }];

// END CALL — simple Twilio TTS farewell
const { callSid } = $input.first().json;

const twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say voice="Polly.Joanna">Thank you for calling Grand Choice Inn and Suites. We look forward to your stay. Goodbye!</Say>
</Response>`;

return [{ json: { twiml, callSid } }];

// -------------------------------------------------------
// VOICE AGENT — AI + Tools + ElevenLabs TTS
// -------------------------------------------------------
const ANTHROPIC_API_KEY  = $env.ANTHROPIC_API_KEY;
const BOOKING_API_URL    = 'http://booking_api:8000';
const BOOKING_API_KEY    = $env.BOOKING_API_KEY;
const WEBHOOK_URL        = $env.N8N_WEBHOOK_URL;

const sessionData = $input.first().json;
const parsedData  = $('Parse Twilio Request').first().json;

const callSid     = parsedData.callSid;
const speechInput = parsedData.speechResult;
const callerPhone = parsedData.fromPhone;
const confidence  = parsedData.confidence || 1.0;

// Low confidence — ask to repeat
if (confidence < 0.4 && speechInput) {
  const retryTwiml = await buildTwiML("I'm sorry, I didn't catch that clearly. Could you please repeat that?", WEBHOOK_URL, BOOKING_API_URL, BOOKING_API_KEY);
  return [{ json: { twiml: retryTwiml, callSid, updatedHistory: [], agentResponse: '' } }];
}

let history = (sessionData.history && Array.isArray(sessionData.history))
  ? sessionData.history : [];

history.push({ role: 'user', content: speechInput });

// ---- TOOLS ----
const tools = [
  {
    name: 'check_availability',
    description: 'Check which room types are available for given check-in and check-out dates. Always call this before making a reservation.',
    input_schema: {
      type: 'object',
      properties: {
        check_in:  { type: 'string', description: 'Check-in date YYYY-MM-DD' },
        check_out: { type: 'string', description: 'Check-out date YYYY-MM-DD' },
        guests:    { type: 'integer', description: 'Number of guests', default: 1 },
        room_type: { type: 'string', description: 'Optional room type code filter' }
      },
      required: ['check_in', 'check_out']
    }
  },
  {
    name: 'get_room_types',
    description: 'Get all room types with prices and amenities. Use this to answer pricing questions.',
    input_schema: { type: 'object', properties: {} }
  },
  {
    name: 'make_reservation',
    description: 'Create a new hotel reservation. Collect ALL required info before calling.',
    input_schema: {
      type: 'object',
      properties: {
        first_name:       { type: 'string' },
        last_name:        { type: 'string' },
        phone:            { type: 'string' },
        email:            { type: 'string' },
        room_type_code:   { type: 'string', description: 'ECONOMY, STD_QUEEN, STD_KING, DBL_QUEEN, DELUXE_KING, SUITE_KING, or ACCESSIBLE' },
        check_in_date:    { type: 'string', description: 'YYYY-MM-DD' },
        check_out_date:   { type: 'string', description: 'YYYY-MM-DD' },
        num_guests:       { type: 'integer' },
        special_requests: { type: 'string' }
      },
      required: ['first_name', 'last_name', 'phone', 'room_type_code', 'check_in_date', 'check_out_date', 'num_guests']
    }
  },
  {
    name: 'get_reservation',
    description: 'Look up a reservation by confirmation code.',
    input_schema: {
      type: 'object',
      properties: { confirmation_code: { type: 'string' } },
      required: ['confirmation_code']
    }
  },
  {
    name: 'cancel_reservation',
    description: 'Cancel a reservation. Always confirm with guest before calling.',
    input_schema: {
      type: 'object',
      properties: { confirmation_code: { type: 'string' } },
      required: ['confirmation_code']
    }
  },
  {
    name: 'get_hotel_info',
    description: 'Get hotel information: address, check-in/out times, amenities, policies, parking, restaurant, etc.',
    input_schema: {
      type: 'object',
      properties: {
        topic: { type: 'string', description: 'Key: checkin_time, checkout_time, parking, wifi, pool, restaurant, pet_policy, cancellation, shuttle, breakfast, accessibility, smoking_policy. Leave empty for all.' }
      }
    }
  }
];

// ---- BOOKING API HELPER ----
async function callAPI(method, path, body = null) {
  const resp = await fetch(`${BOOKING_API_URL}${path}`, {
    method,
    headers: { 'Content-Type': 'application/json', 'x-api-key': BOOKING_API_KEY },
    body: body ? JSON.stringify(body) : undefined,
  });
  const data = await resp.json();
  if (!resp.ok) return { error: true, message: data.detail || `Error ${resp.status}` };
  return data;
}

// ---- TOOL EXECUTOR ----
async function executeTool(name, input) {
  if (name === 'check_availability') {
    const p = new URLSearchParams({ check_in: input.check_in, check_out: input.check_out, guests: input.guests || 1 });
    if (input.room_type) p.append('room_type', input.room_type);
    return callAPI('GET', `/availability?${p}`);
  }
  if (name === 'get_room_types')     return callAPI('GET', '/rooms');
  if (name === 'make_reservation')   return callAPI('POST', '/reservations', input);
  if (name === 'get_reservation')    return callAPI('GET', `/reservations/${input.confirmation_code.toUpperCase()}`);
  if (name === 'cancel_reservation') return callAPI('DELETE', `/reservations/${input.confirmation_code.toUpperCase()}`);
  if (name === 'get_hotel_info') {
    const qs = input.topic ? `?key=${encodeURIComponent(input.topic)}` : '';
    return callAPI('GET', `/hotel-info${qs}`);
  }
  return { error: true, message: `Unknown tool: ${name}` };
}

// ---- ELEVENLABS TTS HELPER ----
async function buildTwiML(text, webhookUrl, apiUrl, apiKey) {
  const safe = text
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');

  let speechContent;
  try {
    const ttsResp = await fetch(`${apiUrl}/tts`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'x-api-key': apiKey },
      body: JSON.stringify({ text }),
    });
    if (ttsResp.ok) {
      const ttsData = await ttsResp.json();
      speechContent = `<Play>${ttsData.audio_url}</Play>`;
    } else {
      speechContent = `<Say voice="Polly.Joanna" language="en-US">${safe}</Say>`;
    }
  } catch (e) {
    speechContent = `<Say voice="Polly.Joanna" language="en-US">${safe}</Say>`;
  }

  return `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Gather input="speech" action="${webhookUrl}/webhook/voice-agent" method="POST"
          speechTimeout="3" language="en-US"
          speechModel="nova2-general"
          enhanced="true">
    ${speechContent}
  </Gather>
  <Redirect method="POST">${webhookUrl}/webhook/voice-agent</Redirect>
</Response>`;
}

// ---- SYSTEM PROMPT ----
const today = new Date().toISOString().split('T')[0];
const systemPrompt = `You are a friendly, professional voice assistant for Grand Choice Inn and Suites hotel. Today is ${today}. Caller phone: ${callerPhone}.

Help guests with: room availability, pricing, making reservations, confirming bookings, cancellations, hotel info and policies.

Rules:
- Short, natural spoken sentences only. No bullet points, no markdown, no special characters.
- Always confirm all reservation details (name, dates, room type, guests, total price) before booking.
- For reservations collect: full name, check-in date, check-out date, room type, number of guests, phone number.
- Speak dates naturally (April 15th) but use YYYY-MM-DD format for tool calls.
- If you cannot help, redirect to front desk: +1-404-555-0190.
- Never make up information. Always use tools for real data.

Room types: ECONOMY $79/night, STD_QUEEN $99, STD_KING $109, DBL_QUEEN $119 up to 4 guests, DELUXE_KING $149, SUITE_KING $199 up to 4 guests, ACCESSIBLE $99.`;

// ---- AI AGENT LOOP ----
async function runAgent() {
  for (let i = 0; i < 8; i++) {
    const resp = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01',
      },
      body: JSON.stringify({
        model: 'claude-sonnet-4-6',
        max_tokens: 1024,
        system: systemPrompt,
        tools,
        messages: history,
      }),
    });

    if (!resp.ok) {
      const err = await resp.text();
      throw new Error(`API error ${resp.status}: ${err}`);
    }

    const data = await resp.json();
    history.push({ role: 'assistant', content: data.content });

    if (data.stop_reason === 'end_turn') {
      const tb = data.content.find(b => b.type === 'text');
      return tb ? tb.text : 'I am sorry, I could not process that. Please call our front desk at 404-555-0190.';
    }

    if (data.stop_reason === 'tool_use') {
      const results = [];
      for (const block of data.content) {
        if (block.type === 'tool_use') {
          let result;
          try { result = await executeTool(block.name, block.input); }
          catch (e) { result = { error: true, message: e.message }; }
          results.push({ type: 'tool_result', tool_use_id: block.id, content: JSON.stringify(result) });
        }
      }
      history.push({ role: 'user', content: results });
    }
  }
  return 'I am sorry, something went wrong. Please call our front desk at 404-555-0190.';
}

const agentResponse = await runAgent();
const twiml = await buildTwiML(agentResponse, WEBHOOK_URL, BOOKING_API_URL, BOOKING_API_KEY);

return [{ json: { twiml, callSid, updatedHistory: history, agentResponse } }];
